import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    # Calculate utility of visiting each node taking into account time windows and avoidance of collective route congestion
    def calculate_utility(current_pos, customer, arrival_time, window_open, window_close):
        # Time window handling
        if arrival_time > window_close:
            time_penalty = (arrival_time - window_close) ** 2
        elif arrival_time < window_open:
            time_penalty = (window_open - arrival_time) ** 2
        else:
            time_penalty = -50  # Reward for hitting within the time window

        # Congestion prediction to avoid routes with high future truck density 
        congestion_penalty = 0
        for pos in all_truck_pos:
            if np.array_equal(pos, current_pos):
                continue
            if calculate_distance(pos, customer) < truck_speed * (window_close - current_time):
                congestion_penalty += 20  # Increasing penalty based on proximity of other trucks

        utility = -time_penalty - congestion_penalty
        return utility

    best_node = None
    max_utility = float('-inf')

    # Evaluate each unvisited customer in terms of utility
    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        utility = calculate_utility(cur_truck_pos, customer, arrival_time, window_open, window_close)

        if utility > max_utility:
            max_utility = utility
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def urgency_penalty(current_time, window_close, window_open, arrival_time):
        time_left = max(window_close - current_time, 0)
        urgency_factor = 1 + (1 / (time_left + 1))  # More urgent as time left diminishes
        if arrival_time > window_close:
            return 100 * (arrival_time - window_close) * urgency_factor
        elif arrival_time < window_open:
            return 50 * (window_open - arrival_time) * urgency_factor
        else:
            return -50 * urgency_factor  # Incentive for hitting the window exactly

    def collaborative_delay(index, current_pos, all_positions, time_to_arrive):
        delay_factor = 0
        for pos in all_positions:
            if np.array_equal(pos, current_pos):
                continue
            other_time = calculate_distance(pos, unvisited_customers[index]) / truck_speed + current_time
            if other_time < time_to_arrive:
                delay_factor += (time_to_arrive - other_time) / truck_speed  # Weighted by how much earlier others can arrive
        return delay_factor

    best_node = None
    min_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        penalty = urgency_penalty(current_time, window_close, window_open, arrival_time)
        collaborative_penalty = collaborative_delay(i, cur_truck_pos, all_truck_pos, arrival_time)

        total_cost = travel_time + penalty + collaborative_penalty

        if total_cost < min_cost:
            min_cost = total_cost
            best_node = i

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def time_to_node(start_pos, end_pos, speed):
        distance = calculate_distance(start_pos, end_pos)
        return distance / speed

    best_node = None
    min_time_cost = float('inf')
    urgency_factor_adjustment = np.random.uniform(0.9, 1.1)  # Random factor to modify urgency slightly

    # Calculate cluster centers for unvisited customers
    num_clusters = min(len(unvisited_customers), 3)  # Maximum of 3 clusters
    if len(unvisited_customers) > 1:
        from sklearn.cluster import KMeans
        kmeans = KMeans(n_clusters=num_clusters)
        kmeans.fit(unvisited_customers)
        cluster_centers = kmeans.cluster_centers_
    else:
        cluster_centers = unvisited_customers  # If only one customer, it is the center

    for i, customer in enumerate(unvisited_customers):
        travel_time = time_to_node(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close)**2
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time) + truck_speed * 0.1  # Penalty with slight advantage to waiting
        else:
            penalty_time = 0  # No penalty for perfect timing

        # Finding the nearest cluster center to current customer to prioritize dense areas
        nearest_cluster_distance = min(calculate_distance(customer, center) for center in cluster_centers)
        urgency = (window_close - arrival_time) * urgency_factor_adjustment  # Adjusted closer to zero implies higher urgency

        time_cost = (arrival_time + penalty_time) / (1.0 + np.exp(-urgency / 30)) + nearest_cluster_distance / 5  # Using softmax-like component for urgency

        if time_cost < min_time_cost:
            min_time_cost = time_cost
            best_node = i

    if best_node is None:
        return None  # Instruct the truck to wait if no optimal node is found
    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def collaborative_cost(index, current_pos, all_positions, time_to_arrive, importance_scale):
        min_other_time = float('inf')
        for pos in all_positions:
            if np.array_equal(pos, current_pos):
                continue
            other_time_to_arrive = calculate_distance(pos, unvisited_customers[index]) / truck_speed + current_time
            if other_time_to_arrive < time_to_arrive:
                min_other_time = min(min_other_time, other_time_to_arrive)
        early_cost = max(0, time_to_arrive - min_other_time)
        return early_cost * importance_scale

    best_node = None
    min_overall_cost = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer) / truck_speed
        arrival_time = current_time + travel_time
        window_open, window_close = time_windows[i]

        if arrival_time > window_close:
            penalty_time = (arrival_time - window_close) * 10
        elif arrival_time < window_open:
            penalty_time = (window_open - arrival_time) * 5
        else:
            penalty_time = -50  # Reward for hitting the time window exactly

        collaborative_importance = 5 if arrival_time < window_open else 3
        collaborative_penalty = collaborative_cost(i, cur_truck_pos, all_truck_pos, arrival_time, collaborative_importance)

        overall_cost = travel_time + penalty_time + collaborative_penalty

        if overall_cost < min_overall_cost:
            min_overall_cost = overall_cost
            best_node = i

    return best_node
